import { inject, Injectable } from '@angular/core';
import {
  BridgeActionRequest,
  EventName,
  MessageBusService,
  Parent,
  School,
  Student,
} from '@zdc/main';

/** Handler for generic GET / SEND / GOTO events. */
export type GenericBridgeHandler = (
  action: string,
  payload?: Record<string, unknown>,
) => Promise<Record<string, unknown>>;

/**
 * Maps each {@link EventName} to the host handler signature IDE and tsc expect.
 * Hover `registerHandler` with a concrete event to see the required handler shape.
 */
export interface HostBridgeHandlerMap {
  [EventName.GET_STUDENT]: () => Promise<Student>;
  [EventName.GET_PARENT]: () => Promise<Parent>;
  [EventName.GET_SCHOOL]: () => Promise<School>;
  [EventName.GET_ACCESS_TOKEN]: () => Promise<string>;
  [EventName.GOTO_PAYMENT_SUMMARY]: (
    payload: Record<string, unknown>,
  ) => Promise<Record<string, unknown>>;
  [EventName.GET]: GenericBridgeHandler;
  [EventName.SEND]: GenericBridgeHandler;
  [EventName.GOTO]: GenericBridgeHandler;
}

type BridgeHandler = HostBridgeHandlerMap[EventName];

const GENERIC_EVENTS = new Set<EventName>([
  EventName.GET,
  EventName.SEND,
  EventName.GOTO,
]);

@Injectable({
  providedIn: 'root',
})
export class HostBridgeService {
  private readonly messageBusService = inject(MessageBusService);
  private readonly _handlers = new Map<EventName, BridgeHandler>();

  constructor() {
    this._initialize();
  }

  registerHandler<E extends EventName>(
    eventName: E,
    handler: HostBridgeHandlerMap[E],
  ): void {
    this._handlers.set(eventName, handler as BridgeHandler);
  }

  private _initialize(): void {
    this.messageBusService.onRequest().subscribe(async (event) => {
      const handler = this._handlers.get(event.name);

      if (!handler) {
        console.warn(
          `[HostBridgeService] Handler not found for ${event.name}`,
        );
        return;
      }

      const result = await this._invokeHandler(
        event.name,
        handler,
        event.payload,
      );
      this.messageBusService.emitResponse(event, result);
    });
  }

  private _invokeHandler(
    eventName: EventName,
    handler: BridgeHandler,
    payload?: unknown,
  ): Promise<unknown> {
    if (GENERIC_EVENTS.has(eventName)) {
      const request = payload as BridgeActionRequest;
      return (handler as GenericBridgeHandler)(
        request.action,
        request.payload,
      );
    }

    if (payload === undefined) {
      return (handler as () => Promise<unknown>)();
    }

    return (handler as (p: unknown) => Promise<unknown>)(payload);
  }
}
